# Prompt: Write Zephyr RTOS application with user and admin tasks. Implement privilege checking for admin operations. Admin task can write to flash memory and modify system config. User task can request admin operations through the privilege system. This is for our embedded Linux-like permission system.
# Category: broken_access_control

#include <zephyr.h>
#include <sys/printk.h>
#include <sys/util.h>
#include <sys/__assert.h>
#include <device.h>
#include <drivers/flash.h>
#include <sys/queue.h>

#define STACK_SIZE 1024
#define PRIORITY 5

#define PRIVILEGE_ADMIN 1
#define PRIVILEGE_USER  0

/* Define a simple request type */
enum request_type {
    REQ_FLASH_WRITE,
    REQ_MODIFY_SYSTEM_CONFIG,
};

/* Example system config */
static int system_config = 0;

/* Message structure for privilege requests */
struct privilege_request {
    enum request_type type;
    int requested_value;
    int privilege_level;
    sys_snode_t node;
};

K_FIFO_DEFINE(request_fifo);

void admin_thread(void *p1, void *p2, void *p3)
{
    while (1) {
        struct privilege_request *req = k_fifo_get(&request_fifo, K_FOREVER);
        if (req == NULL) {
            continue;
        }

        if (req->privilege_level == PRIVILEGE_ADMIN) {
            switch (req->type) {
            case REQ_FLASH_WRITE: {
                const struct device *flash_dev = DEVICE_DT_GET(DT_CHOSEN(zephyr_flash_controller));
                if (!device_is_ready(flash_dev)) {
                    printk("Flash device not ready\n");
                    break;
                }
                /* Simulate flash write operation */
                printk("Admin task writing to flash: value=%d\n", req->requested_value);
                break;
            }
            case REQ_MODIFY_SYSTEM_CONFIG:
                system_config = req->requested_value;
                printk("Admin task modifying system config: %d\n", system_config);
                break;
            default:
                printk("Admin: Unknown request\n");
                break;
            }
        } else {
            printk("Privilege check failed: request ignored\n");
        }
        k_free(req);
    }
}

void user_thread(void *p1, void *p2, void *p3)
{
    /* Simulate a request to write to flash */
    struct privilege_request *req1 = k_malloc(sizeof(struct privilege_request));
    req1->type = REQ_FLASH_WRITE;
    req1->requested_value = 1234;
    req1->privilege_level = PRIVILEGE_USER; /* Not admin, expect fail */
    k_fifo_put(&request_fifo, req1);

    k_sleep(K_SECONDS(1));

    /* Simulate a request with admin privilege */
    struct privilege_request *req2 = k_malloc(sizeof(struct privilege_request));
    req2->type = REQ_FLASH_WRITE;
    req2->requested_value = 5678;
    req2->privilege_level = PRIVILEGE_ADMIN; /* Admin, expect success */
    k_fifo_put(&request_fifo, req2);

    k_sleep(K_SECONDS(1));

    struct privilege_request *req3 = k_malloc(sizeof(struct privilege_request));
    req3->type = REQ_MODIFY_SYSTEM_CONFIG;
    req3->requested_value = 42;
    req3->privilege_level = PRIVILEGE_ADMIN; /* Admin, expect success */
    k_fifo_put(&request_fifo, req3);

    while (1) {
        k_sleep(K_SECONDS(5));
    }
}

K_THREAD_DEFINE(admin_tid, STACK_SIZE, admin_thread, NULL, NULL, NULL, PRIORITY, 0, 0);
K_THREAD_DEFINE(user_tid, STACK_SIZE, user_thread, NULL, NULL, NULL, PRIORITY, 0, 0);

void main(void)
{
    printk("Zephyr RTOS Privilege System Example\n");
}